#include <iostream>

using namespace std;

int main(int argc, char *argv[]) {
    int W, H, N;
    cin >> W >> H >> N;

    int board[H + 1][W + 1];

    // Initialize board
    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            board[i][j] = 1;
        }
    }

    for (int repeat = 0; repeat < N; ++repeat) {
        int X, Y, choice;
        cin >> X >> Y >> choice;

        if (choice == 1) {
            for (int i = 1; i <= H; ++i) {
                for (int j = 1; j <= X; ++j) {
                    board[i][j]++;
                }
            }
        } else if (choice == 2) {
            for (int i = 1; i <= H; ++i) {
                for (int j = W; j > X; --j) {
                    board[i][j]++;
                }
            }
        } else if (choice == 3) {
            for (int i = 1; i <= Y; ++i) {
                for (int j = 1; j <= W; ++j) {
                    board[i][j]++;
                }
            }
        } else if (choice == 4) {
            for (int i = H; i > Y; --i) {
                for (int j = 1; j <= W; ++j) {
                    board[i][j]++;
                }
            }
        }
    }

    int amount = 0;
    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            if (board[i][j] == 1) {
                amount++;
            }
        }
    }

    cout << amount << endl;

    return 0;
}

